# MCP TOOL — policy_results.py
# Reads the OPA results file generated by the most recent
# Conftest run and returns a plain English summary of any
# policy violations found.
# The AI agent calls this when asked about compliance status.
# ══════════════════════════════════════════════════════════════

import json
import os
import subprocess
from pathlib import Path


def get_policy_results(plan_path: str = "tfplan.json") -> dict:
    """
    Runs Conftest against a Terraform plan file and returns
    a structured summary of policy check results.

    Args:
        plan_path: Path to the Terraform plan JSON file

    Returns:
        A dict containing pass/fail counts and violation details
    """

    policies_path = "./policies"

    # Check that the plan file exists before trying to evaluate it
    if not Path(plan_path).exists():
        return {
            "status": "no_plan",
            "message": f"No Terraform plan found at '{plan_path}'. Run 'make validate' first."
        }

    try:
        # Run conftest programmatically using subprocess
        # --output json gives us machine-readable results
        result = subprocess.run(
            ["conftest", "test", plan_path, "--policy", policies_path, "--output", "json"],
            capture_output=True,
            text=True
        )

        # Parse the JSON output from conftest
        # conftest returns an array of result objects, one per policy file
        try:
            results = json.loads(result.stdout)
        except json.JSONDecodeError:
            return {
                "status": "error",
                "message": "Could not parse conftest output. Is conftest installed?"
            }

        # Collect all violations and warnings across all policy files
        all_failures = []
        all_warnings = []
        all_successes = []

        for policy_result in results:
            # Failures block the deployment
            if policy_result.get("failures"):
                for failure in policy_result["failures"]:
                    all_failures.append({
                        "policy": policy_result.get("filename", "unknown"),
                        "message": failure.get("msg", "unknown violation")
                    })

            # Warnings are informational — they don't block deployment
            if policy_result.get("warnings"):
                for warning in policy_result["warnings"]:
                    all_warnings.append({
                        "policy": policy_result.get("filename", "unknown"),
                        "message": warning.get("msg", "unknown warning")
                    })

            # Successes mean a policy file ran with no violations
            if not policy_result.get("failures") and not policy_result.get("warnings"):
                all_successes.append(policy_result.get("filename", "unknown"))

        # Determine overall compliance status
        is_compliant = len(all_failures) == 0

        return {
            "status": "success",
            "compliant": is_compliant,
            "summary": {
                "total_violations": len(all_failures),
                "total_warnings": len(all_warnings),
                "policies_passed": len(all_successes)
            },
            "violations": all_failures,
            "warnings": all_warnings,
            # Plain English verdict for the AI to include in its response
            "verdict": "All policies passed — this configuration is compliant." if is_compliant
                       else f"Found {len(all_failures)} policy violation(s) that must be fixed before deployment."
        }

    except FileNotFoundError:
        return {
            "status": "error",
            "message": "conftest not found. Install it from https://www.conftest.dev"
        }
    except Exception as e:
        return {
            "status": "error",
            "message": str(e)
        }
